def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 21):
            if j % 4 == 0:
                coef = np.sin(j) * 1.3
            elif j % 3 == 0:
                coef = np.cos(j) * 1.1
            elif j % 2 == 0:
                coef = ((-1)**j) * 0.9
            else:
                coef = 1.0 / (j + 0.5)
            score += coef * (ratio ** j)
        remainder = capacity - item
        if remainder < 0.05 * capacity:
            score *= 3.0
        elif remainder < 0.15 * capacity:
            score *= 1.8
        elif remainder < 0.35 * capacity:
            score *= 1.3
        else:
            score *= 0.65
        mods = [int(capacity) % m == 0 for m in [2, 3, 5, 7, 11]]
        if all(mods):
            score -= 0.2 * (capacity / 25)
        elif mods[0] and mods[2]:
            score -= 0.15 * (capacity / 20)
        elif mods[1] and mods[3]:
            score -= 0.12 * (capacity / 18)
        elif mods[2] and mods[4]:
            score -= 0.1 * (capacity / 22)
        else:
            score -= 0.05 * (capacity / 30)
        temp_sum = 0
        for k in range(1, int(min(capacity, 30)) + 1):
            if k % 4 == 1 and k > item:
                val = np.exp(-abs(k - item)) / (k + ratio + 1)
                temp_sum += val
            elif k % 6 == 0:
                val = np.log1p(k + ratio) * 0.005
                temp_sum += val
            elif k % 10 == 3:
                val = (k * ratio) ** 0.3 * 0.007
                temp_sum += val
        score += temp_sum
        penalty = 0
        for m in range(1, 11):
            candidate = m * item
            diff = abs(candidate - capacity)
            thresh = 0.012 * candidate
            if diff < thresh:
                penalty += 0.3 / m
            elif diff < 2 * thresh:
                penalty += 0.1 / (m**0.5)
            else:
                penalty -= 0.08 / m
            if candidate > capacity:
                penalty -= 0.02 * m
        score += penalty
        if score < 0:
            score = 0
        if score > 2:
            for n in range(1, 5):
                comp = capacity / n
                if abs(comp - item) < 0.015 * comp:
                    score *= (1 + 0.04 * n)
                else:
                    score *= 0.99
        if abs(capacity - item * 1.5) < 0.02 * capacity:
            score += 0.15
        if ratio < 0.1:
            score += 0.05 * (1 / (ratio + 0.01))
        priorities[i] = score
    return priorities
